def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val maxTime = if (edges.isEmpty) 0 else edges.map(_.last).max
  var low = 0L
  var high = maxTime
  var answer = high

  def countComponents(t: Long): Long = {
    val adj = Array.fill(n.toInt)(Array[Long]())
    for (edge <- edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val time = edge(2)
      if (time > t) {
        adj(u) += v
        adj(v) += u
      }
    }
    val visited = Array.fill(n.toInt)(false)
    var count = 0L
    for (i <- 0 until n.toInt) {
      if (!visited(i)) {
        count += 1
        dfs(i, adj, visited)
      }
    }
    count
  }

  def dfs(u: Int, adj: Array[Array[Long]], visited: Array[Boolean]): Unit = {
    if (visited(u)) return
    visited(u) = true
    for (v <- adj(u)) {
      val vInt = v.toInt
      if (!visited(vInt)) {
        dfs(vInt, adj, visited)
      }
    }
  }

